def load_bg(b64, size):
    return pygame.transform.smoothscale(
        pygame.image.load(io.BytesIO(base64.b64decode(b64)), "x.jpg"), size).convert()

def load_sprite(b64, h):
    s = pygame.image.load(io.BytesIO(base64.b64decode(b64)), "x.png").convert_alpha()
    ratio = h / s.get_height()
    return pygame.transform.smoothscale(s, (int(s.get_width()*ratio), h))

