def pick_scenario():
    """Pick a random pre-written scenario and return solution + all clues/dialogue."""
    sc = random.choice(SCENARIOS)
    sol = {
        "killer":         sc["killer"],
        "weapon":         sc["weapon"],
        "loc":            sc["murder_location"],
        "murder_loc_key": sc["murder_loc_key"],
        # For facts pool compatibility
        "fw":   next(w for w in WEAPONS if w != sc["weapon"]),
        "inn":  random.choice([k for k in sc["characters"] if k != sc["killer"]]),
        "pair": [],
        "dloc": "",
    }
    return sc, sol

def make_facts(sc):
    return sc["facts"]

def pick_clues(sc):
    """Return the location clues for this scenario."""
    return sc["location_clues"]

def pick_dialogue(sc):
    """Return each character's alibi/motive/rel for this scenario."""
    result = {}
    for key, data in sc["characters"].items():
        result[key] = {
            "alibi":    data["alibi"],
            "motive":   data["motive"] + (" But I did not murder him." if key != sc["killer"] else ""),
            "rel":      data["rel"],
            "loc_hint": data["loc"],
            "wpn_hint": data["object"],
        }
    return result


def wrap(text, font, maxw):
    words = text.split(); lines = []; cur = []
    for w in words:
        if font.size(" ".join(cur+[w]))[0] <= maxw: cur.append(w)
        else:
            if cur: lines.append(" ".join(cur))
            cur = [w]
    if cur: lines.append(" ".join(cur))
    return lines or [""]

def shadow_rect(surf, rect, bg, border, bw=3):
    pygame.draw.rect(surf, BLACK, pygame.Rect(rect.x+4,rect.y+4,rect.w,rect.h))
    pygame.draw.rect(surf, bg, rect)
    pygame.draw.rect(surf, border, rect, bw)

def fact_box(surf, F, label, lines, x, y, w):
    lh = F["body"].get_linesize()
    bh = 10 + F["sm"].get_linesize() + len(lines)*lh + 12
    r  = pygame.Rect(x, y, w, bh)
    pygame.draw.rect(surf, BLACK, pygame.Rect(r.x+3,r.y+3,r.w,r.h))
    pygame.draw.rect(surf, DRED, r); pygame.draw.rect(surf, RED, r, 3)
    surf.blit(F["sm"].render(label, True, RED), (r.x+12, r.y+8))
    ty = r.y+8+F["sm"].get_linesize()+3
    for ln in lines:
        surf.blit(F["body"].render(ln, True, (255,175,175)), (r.x+12, ty)); ty += lh
    return y+bh+12

def clue_box(surf, F, label, lines, x, y, w):
    lh = F["body"].get_linesize()
    bh = 10 + F["sm"].get_linesize() + len(lines)*lh + 12
    r  = pygame.Rect(x, y, w, bh)
    pygame.draw.rect(surf, (16,14,3), r)
    pygame.draw.rect(surf, YELLOW, pygame.Rect(x, y, 4, bh))
    surf.blit(F["sm"].render(label, True, YELLOW), (r.x+10, r.y+8))
    ty = r.y+8+F["sm"].get_linesize()+3
    for ln in lines:
        surf.blit(F["body"].render(ln, True, CREAM), (r.x+10, ty)); ty += lh
    return y+bh+10

# ── BUTTON ────────────────────────────────────────────────────────────────────
class Btn:
    def __init__(self, r, label, font, danger=False):
        self.r=pygame.Rect(r); self.label=label; self.font=font
        self.danger=danger; self.hov=False
    def update(self, pos): self.hov = self.r.collidepoint(pos)
    def hit(self, pos):    return self.r.collidepoint(pos)
    def draw(self, surf):
        bg = RED if self.danger else YELLOW; fg = WHITE if self.danger else DARK
        off = (-2,-2) if self.hov else (0,0)
        pygame.draw.rect(surf, BLACK, pygame.Rect(self.r.x+3+off[0],self.r.y+3+off[1],self.r.w,self.r.h))
        r = self.r.move(off)
        pygame.draw.rect(surf, bg, r); pygame.draw.rect(surf, BLACK, r, 3)
        ts = self.font.render(self.label, True, fg)
        surf.blit(ts, ts.get_rect(center=r.center))

# ── SCROLL PANEL ──────────────────────────────────────────────────────────────
class SP:
    def __init__(self, rect):
        self.rect=pygame.Rect(rect); self.scroll=0; self.surf=None; self.ch=0
    def set(self, surf, ch):
        self.surf=surf; self.ch=max(ch, self.rect.h); self.scroll=0
    def wheel(self, ev, mouse_pos=None):
        pos = mouse_pos if mouse_pos is not None else pygame.mouse.get_pos()
        if self.surf and self.rect.collidepoint(pos):
            self.scroll=max(0,min(self.ch-self.rect.h,self.scroll-ev.y*26))
    def draw(self, screen):
        if self.surf is None: return
        rh=self.rect.h; sh=self.surf.get_height()
        sy=int(max(0,min(self.scroll,sh-rh))); vis=min(rh,sh-sy)
        if vis<=0: return
        tmp=pygame.Surface((self.rect.w,vis)); tmp.blit(self.surf,(0,-sy))
        screen.blit(tmp, self.rect.topleft)
        if sh>rh:
            bh=max(24,int(rh*rh/sh)); ratio=sy/max(1,sh-rh)
            by=self.rect.y+int(ratio*(rh-bh))
            pygame.draw.rect(screen,DGREY, pygame.Rect(self.rect.right-10,self.rect.y,10,rh))
            pygame.draw.rect(screen,YELLOW,pygame.Rect(self.rect.right-10,by,10,bh))

# ── MODAL ─────────────────────────────────────────────────────────────────────
class Modal:
    MX=70; MY=46; HDR=52
    def __init__(self, F):
        self.F=F; self.vis=False; self.title=""; self.ikey=None; self.ibtns=[]
        self.MW=W-self.MX*2; self.MH=H-self.MY*2
        self.body=pygame.Rect(self.MX,self.MY+self.HDR,self.MW,self.MH-self.HDR)
        self.sp=SP(self.body)
        self.close_btn=Btn((self.MX+self.MW-110,self.MY+10,100,32),"X CLOSE",F["sm"],danger=True)
    def open(self, title, surf, ch, ikey=None, ibtns=None):
        if surf.get_width()!=self.MW:
            s2=pygame.Surface((self.MW,surf.get_height()),pygame.SRCALPHA)
            s2.fill(PANEL); s2.blit(surf,(0,0)); surf=s2
        self.title=title; self.sp.set(surf,ch); self.vis=True
        self.ikey=ikey; self.ibtns=ibtns or []
    def handle(self, ev, game, cpos=None):
        pos = cpos or (ev.pos if hasattr(ev,'pos') else (0,0))
        if not self.vis: return False
        if ev.type==pygame.MOUSEWHEEL: self.sp.wheel(ev, pos)
        if ev.type==pygame.MOUSEMOTION: self.close_btn.update(pos)
        if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
            if self.close_btn.hit(pos): self.vis=False; return True
            if self.ikey and self.body.collidepoint(pos):
                rx=pos[0]-self.body.x; ry=pos[1]-self.body.y+int(self.sp.scroll)
                for qkey,qr in self.ibtns:
                    if qr.collidepoint(rx,ry): game.answer_q(self.ikey,qkey); return True
            if pygame.Rect(self.MX,self.MY,self.MW,self.MH).collidepoint(pos): return True
        return False
    def draw(self, screen):
        if not self.vis: return
        ov=pygame.Surface((W,H),pygame.SRCALPHA); ov.fill((0,0,0,190)); screen.blit(ov,(0,0))
        shadow_rect(screen,pygame.Rect(self.MX,self.MY,self.MW,self.MH),PANEL,YELLOW,4)
        pygame.draw.rect(screen,YELLOW,pygame.Rect(self.MX,self.MY,self.MW,self.HDR))
        screen.blit(self.F["med"].render(self.title,True,DARK),(self.MX+14,self.MY+14))
        self.close_btn.draw(screen)
        pygame.draw.rect(screen,PANEL,self.body)
        self.sp.draw(screen)

# ── CONTENT BUILDERS ─────────────────────────────────────────────────────────
PAD=18

def build_loc(key, clues, MW, F):
    inner=MW-PAD*2; total=PAD; rows=[]
    for i,clue in enumerate(clues):
        lbl="CLUE "+str(i+1)+" — "+LOCATION_CLUES[key]["name"].upper()
        wl=wrap(clue,F["body"],inner-22)
        rows.append((lbl,wl))
        total+=10+F["sm"].get_linesize()+len(wl)*F["body"].get_linesize()+12+10
    total+=PAD
    s=pygame.Surface((MW,max(total,300))); s.fill(PANEL)
    y=PAD
    for lbl,wl in rows: y=clue_box(s,F,lbl,wl,PAD,y,inner)
    return s,total

def build_interview(key, answer, sprite, MW, F):
    PAD2=20; inner=MW-PAD2*2
    sp_w=sprite.get_width() if sprite else 0
    sp_h=sprite.get_height() if sprite else 0
    bub_w=inner-sp_w-16 if sprite else inner
    role_h=F["sm"].get_linesize()+12
    bubble_h=0
    if answer:
        wl_ans=wrap(answer,F["body"],bub_w-36)
        bubble_h=36+len(wl_ans)*F["body"].get_linesize()+46
    left_h=role_h+bubble_h
    top_h=max(sp_h+16,left_h)+12
    qs=[("alibi","Where were you that night?"),
        ("motive","Did you have an issue with Professor I?"),
        ("rel","What was your relationship with the victim?")]
    q_h=len(qs)*(F["sm"].get_linesize()+26)
    total=PAD2+top_h+6+3+14+q_h+PAD2+20
    s=pygame.Surface((MW,max(total,420))); s.fill(PANEL)
    y=PAD2
    if sprite: s.blit(sprite,(MW-sp_w-PAD2,y))
    s.blit(F["sm"].render(SUSPECT_DATA[key]["role"],True,GREY),(PAD2,y))
    y+=F["sm"].get_linesize()+12
    if answer:
        wl_ans=wrap(answer,F["body"],bub_w-36)
        bh=36+len(wl_ans)*F["body"].get_linesize()
        br=pygame.Rect(PAD2,y,bub_w,bh)
        pygame.draw.rect(s,BLACK,pygame.Rect(br.x+4,br.y+4,br.w,br.h))
        pygame.draw.rect(s,WHITE,br); pygame.draw.rect(s,BLACK,br,4)
        tx=PAD2+28
        pygame.draw.polygon(s,BLACK,[(tx,br.bottom),(tx+14,br.bottom),(tx+7,br.bottom+14)])
        pygame.draw.polygon(s,WHITE,[(tx+2,br.bottom),(tx+12,br.bottom),(tx+7,br.bottom+10)])
        ty=br.y+18
        for ln in wl_ans: s.blit(F["body"].render(ln,True,BLACK),(br.x+18,ty)); ty+=F["body"].get_linesize()
        s.blit(F["sm"].render("— "+SUSPECT_DATA[key]["name"],True,YELLOW),(PAD2+6,br.bottom+18))
        y+=bh+46
    y=max(y,PAD2+sp_h+16)
    pygame.draw.rect(s,YELLOW,pygame.Rect(PAD2,y,inner,3)); y+=14
    ibtns=[]
    for qkey,ql in qs:
        bh2=F["sm"].get_linesize()+24; br2=pygame.Rect(PAD2,y,inner,bh2)
        pygame.draw.rect(s,BLACK,pygame.Rect(br2.x+3,br2.y+3,br2.w,br2.h))
        pygame.draw.rect(s,CREAM,br2); pygame.draw.rect(s,BLACK,br2,3)
        s.blit(F["sm"].render(ql,True,DARK),(br2.x+16,br2.y+12))
        ibtns.append((qkey,br2)); y+=bh2+10
    return s,total,ibtns

def build_facts(facts, MW, F):
    inner=MW-PAD*2; total=PAD+F["sm"].get_linesize()+14+3+14; rows=[]
    for i,fact in enumerate(facts):
        wl=wrap(fact,F["body"],inner-26)
        rows.append(("CONFIRMED FACT "+str(i+1),wl))
        total+=10+F["sm"].get_linesize()+len(wl)*F["body"].get_linesize()+12+12
    total+=PAD
    s=pygame.Surface((MW,max(total,300))); s.fill(PANEL)
    y=PAD
    s.blit(F["sm"].render("Confirmed by investigators. These facts are not in dispute.",True,GREY),(PAD,y))
    y+=F["sm"].get_linesize()+14
    pygame.draw.rect(s,YELLOW,pygame.Rect(PAD,y,inner,3)); y+=14
    for lbl,wl in rows: y=fact_box(s,F,lbl,wl,PAD,y,inner)
    return s,total

def build_notebook(facts, visited, clues_seen, notebook, MW, F):
    inner=MW-PAD*2; FM,FS,FB=F["med"],F["sm"],F["body"]
    def sh(): return FM.get_linesize()+4+3+14
    def fh(wl): return 10+FS.get_linesize()+len(wl)*FB.get_linesize()+12+12
    def ch(wl): return 10+FS.get_linesize()+len(wl)*FB.get_linesize()+12+10
    def cardh(): return PAD+FM.get_linesize()+FS.get_linesize()*3+FB.get_linesize()*3+PAD+12
    total=PAD+sh()
    for f in facts: total+=fh(wrap(f,FB,inner-26))
    total+=10+sh()
    if not visited: total+=FB.get_linesize()+10
    else:
        for lk in visited:
            for c in clues_seen.get(lk,[]): total+=ch(wrap(c,FB,inner-26))
    total+=10+sh()+len(SUSPECT_DATA)*cardh()+PAD*2
    s=pygame.Surface((MW,max(total,600))); s.fill(PANEL)
    y=PAD
    def section(title,yy):
        s.blit(FM.render(title,True,YELLOW),(PAD,yy)); yy+=FM.get_linesize()+4
        pygame.draw.rect(s,YELLOW,pygame.Rect(PAD,yy,inner,3)); return yy+14
    y=section("CASE FACTS",y)
    for i,f in enumerate(facts): y=fact_box(s,F,"FACT "+str(i+1),wrap(f,FB,inner-26),PAD,y,inner)
    y+=10; y=section("CLUES COLLECTED",y)
    if not visited:
        s.blit(FB.render("Visit locations to collect clues.",True,GREY),(PAD,y)); y+=FB.get_linesize()+10
    else:
        for lk in visited:
            for ci,clue in enumerate(clues_seen.get(lk,[])):
                lbl="["+LOCATION_CLUES[lk]["name"]+"] Clue "+str(ci+1)
                y=clue_box(s,F,lbl,wrap(clue,FB,inner-26),PAD,y,inner)
    y+=10; y=section("SUSPECT NOTES  (right-click portrait to edit)",y)
    for sk in SUSPECT_DATA:
        sd=SUSPECT_DATA[sk]; nb=notebook[sk]
        bh=PAD+FM.get_linesize()+FS.get_linesize()*3+FB.get_linesize()*3+PAD
        br=pygame.Rect(PAD,y,inner,bh)
        pygame.draw.rect(s,DGREY,br); pygame.draw.rect(s,GOLD,br,2)
        ns=FM.render(sd["name"].upper(),True,YELLOW); s.blit(ns,(br.x+12,br.y+10))
        rs=FS.render(sd["role"],True,GREY); s.blit(rs,(br.x+12+ns.get_width()+12,br.y+14))
        ty=br.y+10+FM.get_linesize()+6
        for lbl,val in [("Suspected location:",nb["loc"] or "not set"),
                         ("Suspected weapon:",  nb["wpn"] or "not set"),
                         ("Notes:",             nb["notes"] or "none")]:
            s.blit(FS.render(lbl,True,GREY),(br.x+12,ty))
            s.blit(FB.render(val,True,CREAM),(br.x+240,ty))
            ty+=max(FS.get_linesize(),FB.get_linesize())+4
        y+=bh+12
    return s,total

# ── ACCUSATION ────────────────────────────────────────────────────────────────
class Accuse:
    def __init__(self,F):
        self.F=F; self.vis=False; self.step=0; self.picks=[0,0,0]; self.result=None
        self.sk=list(SUSPECT_DATA); self.lk=list(LOCATION_CLUES)
        self.back =Btn((80,H-72,140,42),"< BACK",F["sm"])
        self.nxt  =Btn((W-220,H-72,140,42),"NEXT >",F["sm"])
        self.file =Btn((W//2-140,H-72,280,42),"FILE ACCUSATION",F["sm"],danger=True)
        self.btn_again=Btn((W//2-220,H-120,210,52),"PLAY AGAIN",F["med"])
        self.btn_quit =Btn((W//2+20, H-120,210,52),"EXIT GAME", F["med"],danger=True)
    def show(self): self.vis=True; self.step=0; self.picks=[0,0,0]; self.result=None
    def opts(self):
        if self.step==0: return [SUSPECT_DATA[k]["name"] for k in self.sk]
        if self.step==1: return [LOCATION_CLUES[k]["name"] for k in self.lk]
        return WEAPONS
    def handle(self,ev,sol,game,cpos=None):
        pos = cpos or (ev.pos if hasattr(ev,'pos') else (0,0))
        if not self.vis: return
        if self.result is not None:
            if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
                if self.btn_again.hit(pos): game.restart(); return
                if self.btn_quit.hit(pos): pygame.quit(); sys.exit()
            if ev.type==pygame.MOUSEMOTION:
                self.btn_again.update(pos); self.btn_quit.update(pos)
            return
        opts=self.opts()
        if ev.type==pygame.KEYDOWN:
            if ev.key==pygame.K_UP:   self.picks[self.step]=(self.picks[self.step]-1)%len(opts)
            if ev.key==pygame.K_DOWN: self.picks[self.step]=(self.picks[self.step]+1)%len(opts)
            if ev.key in(pygame.K_RETURN,pygame.K_RIGHT): self._go(sol)
            if ev.key==pygame.K_LEFT and self.step>0: self.step-=1
        if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
            for i in range(len(opts)):
                if pygame.Rect(W//2-270,158+i*52,540,44).collidepoint(pos): self.picks[self.step]=i
            if self.step>0 and self.back.hit(pos): self.step-=1
            if self.step<2 and self.nxt.hit(pos): self._go(sol)
            if self.step==2 and self.file.hit(pos): self._go(sol)
        if ev.type==pygame.MOUSEMOTION:
            self.back.update(pos); self.nxt.update(pos); self.file.update(pos)
    def _go(self,sol):
        if self.step<2: self.step+=1
        else:
            sk=self.sk[self.picks[0]]; lk=self.lk[self.picks[1]]; wk=WEAPONS[self.picks[2]]
            ck=sk==sol["killer"]; cl=LOCATION_CLUES[lk]["name"]==sol["loc"]; cw=wk==sol["weapon"]
            self.result={"win":ck and cl and cw,"ck":ck,"cl":cl,"cw":cw,
                         "killer":SUSPECT_DATA[sol["killer"]]["name"],"loc":sol["loc"],"wpn":sol["weapon"]}
    def draw(self,screen,F):
        if not self.vis: return
        ov=pygame.Surface((W,H),pygame.SRCALPHA); ov.fill((0,0,0,220)); screen.blit(ov,(0,0))
        if self.result:
            r=self.result; col=GREEN if r["win"] else RED
            screen.blit(F["title"].render("CASE SOLVED!" if r["win"] else "WRONG ACCUSATION",True,col),
                        F["title"].render("x",True,col).get_rect().__class__(0,0,0,0).__class__.__mro__[0].__new__(pygame.Rect))
            t=F["title"].render("CASE SOLVED!" if r["win"] else "WRONG ACCUSATION",True,col)
            screen.blit(t,t.get_rect(centerx=W//2,y=90))
            lines=(["You found the killer!",""] if r["win"] else ["The killer walks free.",""])+[
                "Killer:   "+("CORRECT" if r["ck"] else "WRONG")+"  ->  "+r["killer"],
                "Location: "+("CORRECT" if r["cl"] else "WRONG")+"  ->  "+r["loc"],
                "Weapon:   "+("CORRECT" if r["cw"] else "WRONG")+"  ->  "+r["wpn"],""]
            y=175
            for ln in lines:
                ts=F["body"].render(ln,True,CREAM); screen.blit(ts,ts.get_rect(centerx=W//2,y=y)); y+=F["body"].get_linesize()+8
            self.btn_again.draw(screen); self.btn_quit.draw(screen)
            return
        t=F["title"].render("MAKE YOUR ACCUSATION",True,RED)
        screen.blit(t,t.get_rect(centerx=W//2,y=44))
        for i,st in enumerate(["1. KILLER","2. LOCATION","3. WEAPON"]):
            screen.blit(F["sm"].render(st,True,YELLOW if i==self.step else GREY),
                        F["sm"].render(st,True,GREY).get_rect(centerx=W//2-230+i*230,y=104))
        for i,opt in enumerate(self.opts()):
            rr=pygame.Rect(W//2-270,158+i*52,540,44)
            bg=YELLOW if i==self.picks[self.step] else DGREY; fg=DARK if i==self.picks[self.step] else CREAM
            pygame.draw.rect(screen,BLACK,pygame.Rect(rr.x+3,rr.y+3,rr.w,rr.h))
            pygame.draw.rect(screen,bg,rr); pygame.draw.rect(screen,BLACK,rr,3)
            screen.blit(F["body"].render(opt,True,fg),(rr.x+16,rr.y+12))
            if i==self.picks[self.step]: screen.blit(F["body"].render(">",True,DARK),(rr.x-22,rr.y+12))
        if self.step>0: self.back.draw(screen)
        if self.step<2: self.nxt.draw(screen)
        else: self.file.draw(screen)
        hint=F["sm"].render("Arrow keys + Enter to navigate",True,GREY)
        screen.blit(hint,hint.get_rect(centerx=W//2,y=H-106))

# ── NOTEBOOK EDITOR ───────────────────────────────────────────────────────────
class NbEdit:
    def __init__(self,F):
        self.F=F; self.vis=False; self.key=None; self.field=0
        self.picks=[0,0]; self.notes=""; self.lk=list(LOCATION_CLUES)
        self.done=Btn((W//2-80,H-72,160,42),"DONE",F["sm"])
    def show(self,key,nb):
        self.vis=True; self.key=key; self.field=0; self.notes=nb[key]["notes"]
        lnames=[LOCATION_CLUES[k]["name"] for k in self.lk]
        self.picks[0]=lnames.index(nb[key]["loc"]) if nb[key]["loc"] in lnames else 0
        self.picks[1]=WEAPONS.index(nb[key]["wpn"]) if nb[key]["wpn"] in WEAPONS else 0
    def _save(self,nb):
        nb[self.key]["loc"]=LOCATION_CLUES[self.lk[self.picks[0]]]["name"]
        nb[self.key]["wpn"]=WEAPONS[self.picks[1]]; nb[self.key]["notes"]=self.notes
    def handle(self,ev,nb,cpos=None):
        pos = cpos or (ev.pos if hasattr(ev,'pos') else (0,0))
        if not self.vis: return False
        if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
            if self.done.hit(pos): self._save(nb); self.vis=False; return True
            for i,tr in enumerate([pygame.Rect(50+i*240,108,220,38) for i in range(3)]):
                if tr.collidepoint(pos): self._save(nb); self.field=i
            if self.field in(0,1):
                opts=self.lk if self.field==0 else WEAPONS
                for i in range(len(opts)):
                    if pygame.Rect(W//2-250,165+i*48,500,42).collidepoint(pos): self.picks[self.field]=i
        if ev.type==pygame.KEYDOWN:
            if ev.key==pygame.K_ESCAPE: self._save(nb); self.vis=False
            elif ev.key==pygame.K_TAB: self._save(nb); self.field=(self.field+1)%3
            elif self.field in(0,1):
                n=len(self.lk if self.field==0 else WEAPONS)
                if ev.key==pygame.K_UP:   self.picks[self.field]=(self.picks[self.field]-1)%n
                if ev.key==pygame.K_DOWN: self.picks[self.field]=(self.picks[self.field]+1)%n
            elif self.field==2:
                if ev.key==pygame.K_BACKSPACE: self.notes=self.notes[:-1]
                elif ev.unicode and len(self.notes)<120: self.notes+=ev.unicode
        if ev.type==pygame.MOUSEMOTION: self.done.update(pos)
        return True
    def draw(self,screen):
        if not self.vis: return
        ov=pygame.Surface((W,H),pygame.SRCALPHA); ov.fill((0,0,0,215)); screen.blit(ov,(0,0))
        F=self.F; s=SUSPECT_DATA[self.key]
        t=F["title"].render("EDIT NOTES: "+s["name"].upper(),True,YELLOW)
        screen.blit(t,t.get_rect(centerx=W//2,y=50))
        for i,tl in enumerate(["LOCATION","WEAPON","NOTES"]):
            tr=pygame.Rect(50+i*240,108,220,38)
            bg=YELLOW if i==self.field else DGREY; fg=DARK if i==self.field else CREAM
            pygame.draw.rect(screen,bg,tr); pygame.draw.rect(screen,BLACK,tr,2)
            screen.blit(F["sm"].render(tl,True,fg),F["sm"].render(tl,True,fg).get_rect(center=tr.center))
        y=165
        if self.field in(0,1):
            opts=[LOCATION_CLUES[k]["name"] for k in self.lk] if self.field==0 else WEAPONS
            for i,opt in enumerate(opts):
                rr=pygame.Rect(W//2-250,y,500,42)
                bg=YELLOW if i==self.picks[self.field] else DGREY; fg=DARK if i==self.picks[self.field] else CREAM
                pygame.draw.rect(screen,bg,rr); pygame.draw.rect(screen,BLACK,rr,2)
                screen.blit(F["body"].render(opt,True,fg),(rr.x+16,rr.y+11)); y+=48
        else:
            box=pygame.Rect(W//2-250,y,500,46)
            pygame.draw.rect(screen,DARK,box); pygame.draw.rect(screen,YELLOW,box,2)
            screen.blit(F["body"].render(self.notes+"|",True,CREAM),(box.x+12,box.y+12))
            h=F["sm"].render("Type notes  |  Tab=switch field  |  Esc=close",True,GREY)
            screen.blit(h,h.get_rect(centerx=W//2,y=y+60))
        self.done.draw(screen)

# ── HOW TO PLAY ───────────────────────────────────────────────────────────────
RULES = [
    ("OBJECTIVE",
     "Professor I has been murdered. Your job: identify the killer, the location of the murder, and the weapon used. Get all three right to solve the case."),
    ("LOCATIONS",
     "Click the pulsing red markers on the campus map to visit a location and collect clues. Markers turn green once visited. Each location has 2 random clues per round."),
    ("SUSPECTS",
     "Click any character portrait at the bottom bar to open an interview. Ask about their alibi, their motive, and their relationship with Professor I. Dialogue changes every round."),
    ("NOTEBOOK",
     "Click NOTEBOOK in the top bar to review all clues you have found and the confirmed case facts. Right-click any character portrait to record your suspected location, weapon, and personal notes for that suspect."),
    ("CASE FACTS",
     "Two confirmed facts are shown on the briefing screen and in your notebook. These are guaranteed true. One may directly name the location or clear a suspect."),
    ("ACCUSATION",
     "Click ACCUSE when ready. Step through killer, location, and weapon. Use BACK to change your mind. You only get one shot — make it count."),
    ("HOW TO WIN",
     "The mystery is solvable every round. The killer always has the most incriminating motive. The case facts always include at least one strong lead. Combine clues, dialogue, and facts to narrow it down."),
    ("CONTROLS",
     "Left-click: interact with locations and suspects  |  Right-click portrait: edit your notebook notes  |  Scroll wheel: scroll panels  |  F11 or Alt+Enter: toggle fullscreen  |  Esc: close any panel  |  H: open this screen"),
]

class HelpScreen:
    def __init__(self, F):
        self.F=F; self.vis=False; self.scroll=0
        MW=780; PAD2=24; inner=MW-PAD2*2
        y=PAD2
        for title,body in RULES:
            wl=wrap(body,F["body"],inner-20)
            y+=F["med"].get_linesize()+8+len(wl)*F["body"].get_linesize()+8+16
        y+=PAD2
        self._ch=y; self._MW=MW
        s=pygame.Surface((MW,max(y,400))); s.fill(PANEL)
        y2=PAD2
        for title,body in RULES:
            ts=F["med"].render(title,True,YELLOW); s.blit(ts,(PAD2,y2)); y2+=F["med"].get_linesize()+6
            wl=wrap(body,F["body"],inner-20)
            for ln in wl: s.blit(F["body"].render(ln,True,CREAM),(PAD2+10,y2)); y2+=F["body"].get_linesize()
            pygame.draw.rect(s,DGREY,pygame.Rect(PAD2,y2+6,inner,2)); y2+=18
        self._surf=s
        self.done=Btn((W//2-80,H-90,160,44),"GOT IT",F["sm"])

    def toggle(self): self.vis=not self.vis; self.scroll=0
    def handle(self,ev,cpos=None):
        pos = cpos or (ev.pos if hasattr(ev,'pos') else (0,0))
        if not self.vis: return False
        MX=W//2-self._MW//2; MY=55; MH=H-145
        panel=pygame.Rect(MX,MY,self._MW,MH)
        if ev.type==pygame.MOUSEWHEEL:
            # MOUSEWHEEL has no pos - always check if mouse is over panel
            if panel.collidepoint(pygame.mouse.get_pos()):
                self.scroll=max(0,min(self._ch-MH,self.scroll-ev.y*24))
        if ev.type==pygame.MOUSEMOTION: self.done.update(pos)
        if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
            if self.done.hit(pos): self.vis=False; return True
            if not panel.collidepoint(pos): self.vis=False; return True
            return True
        if ev.type==pygame.KEYDOWN and ev.key in(pygame.K_ESCAPE,pygame.K_h): self.vis=False
        return self.vis

    def draw(self,screen,F):
        if not self.vis: return
        MW=self._MW; MX=W//2-MW//2; MY=55; MH=H-145
        ov=pygame.Surface((W,H),pygame.SRCALPHA); ov.fill((0,0,0,200)); screen.blit(ov,(0,0))
        shadow_rect(screen,pygame.Rect(MX,MY,MW,MH),PANEL,YELLOW,4)
        HDR=52
        pygame.draw.rect(screen,YELLOW,pygame.Rect(MX,MY,MW,HDR))
        t=F["title"].render("HOW TO PLAY",True,DARK); screen.blit(t,t.get_rect(centerx=MX+MW//2,y=MY+12))
        body_r=pygame.Rect(MX,MY+HDR,MW,MH-HDR)
        pygame.draw.rect(screen,PANEL,body_r)
        if self._surf:
            sh=self._surf.get_height(); rh=body_r.h
            sy=int(max(0,min(self.scroll,sh-rh))); vis=min(rh,sh-sy)
            if vis>0:
                tmp=pygame.Surface((MW,vis)); tmp.blit(self._surf,(0,-sy)); screen.blit(tmp,body_r.topleft)
            if sh>rh:
                bh=max(24,int(rh*rh/sh)); by=body_r.y+int((sy/max(1,sh-rh))*(rh-bh))
                pygame.draw.rect(screen,DGREY, pygame.Rect(body_r.right-10,body_r.y,10,rh))
                pygame.draw.rect(screen,YELLOW,pygame.Rect(body_r.right-10,by,10,bh))
        pygame.draw.rect(screen,YELLOW,pygame.Rect(MX,MY,MW,MH),4)
        self.done.draw(screen)

# ── MAIN GAME ─────────────────────────────────────────────────────────────────
class Game:
    I1="i1"; I2="i2"; PLAY="play"

    def __init__(self):
        pygame.init()
        self.fullscreen=False
        self.screen=pygame.display.set_mode((W,H),pygame.RESIZABLE)
        pygame.display.set_caption("CAMPUS KILLER — IE University")
        self.clock=pygame.time.Clock()
        self.canvas=pygame.Surface((W,H))
        fn="couriernew"
        self.F={
            "title":pygame.font.SysFont(fn,34,bold=True),
            "med":  pygame.font.SysFont(fn,26,bold=True),
            "body": pygame.font.SysFont(fn,21),
            "sm":   pygame.font.SysFont(fn,17,bold=True),
        }
        print("Loading assets...")
        self.bg=load_bg(_BG,(W,H))
        self.sprites={
            "zura":  load_sprite(_ZURA,  120),
            "simon": load_sprite(_SIMON, 120),
            "carla": load_sprite(_CARLA, 120),
            "dani":  load_sprite(_DANI,  120),
            "hector":load_sprite(_HECTOR,120),
        }
        self._new_game()
        GH=H-HUD_H-BAR_H
        self.hs={}
        for key,(fx,fy) in HOTSPOT_POS.items():
            self.hs[key]={"key":key,"cx":int(fx*W),"cy":HUD_H+int(fy*GH),
                          "vis":False,"pulse":0,"r":12,
                          "label":LOCATION_CLUES[key]["name"].upper()}
        n=len(SUSPECT_DATA); cw=W//n
        self.cards=[{"key":k,"rect":pygame.Rect(i*cw,H-BAR_H,cw,BAR_H),"hov":False,"done":False}
                    for i,(k,_) in enumerate(SUSPECT_DATA.items())]
        self.btn_nb =Btn((W-560,10,150,32),"NOTEBOOK",  self.F["sm"])
        self.btn_cf =Btn((W-400,10,160,32),"CASE FACTS",self.F["sm"])
        self.btn_acc=Btn((W-230,10,170,32),"ACCUSE",    self.F["sm"],danger=True)
        self.btn_beg=Btn((W//2-210,H-170,420,62),"BEGIN INVESTIGATION",  self.F["med"])
        self.btn_inv=Btn((W//2-225,H-170,450,62),"INVESTIGATE THE SCENE",self.F["med"])
        self.modal  =Modal(self.F)
        self.accuse =Accuse(self.F)
        self.nbedit =NbEdit(self.F)
        self.help   =HelpScreen(self.F)
        self.hov_hs =None
        # ? button — always top-left
        self.btn_q  =Btn((14,10,42,32),"?",self.F["med"])
        print("Ready. Good luck, detective.")

    def _new_game(self):
        self.sc, self.sol = pick_scenario()
        self.facts    = make_facts(self.sc)
        self.clues    = pick_clues(self.sc)
        self.dialogue = pick_dialogue(self.sc)
        self.visited  = []
        self.notebook = {k:{"loc":"","wpn":"","notes":""} for k in SUSPECT_DATA}
        self.state    = self.I1

    def restart(self):
        self._new_game()
        for h in self.hs.values(): h["vis"]=False; h["pulse"]=0
        for c in self.cards: c["hov"]=False; c["done"]=False
        self.modal.vis=False; self.accuse.vis=False; self.nbedit.vis=False; self.help.vis=False

    def toggle_fs(self):
        self.fullscreen=not self.fullscreen
        self.screen=pygame.display.set_mode((0,0) if self.fullscreen else (W,H),
                                             pygame.FULLSCREEN if self.fullscreen else pygame.RESIZABLE)

    def _MW(self): return self.modal.MW

    def open_loc(self,key):
        s,h=build_loc(key,self.clues[key],self._MW(),self.F)
        self.modal.open("  "+LOCATION_CLUES[key]["name"].upper(),s,h)

    def open_interview(self,key,ans=None):
        sp=self.sprites[key]
        s,h,ib=build_interview(key,ans,sp,self._MW(),self.F)
        self.modal.open("  INTERVIEW — "+SUSPECT_DATA[key]["name"].upper(),s,h,ikey=key,ibtns=ib)
        for c in self.cards:
            if c["key"]==key: c["done"]=True

    def answer_q(self,key,qt):
        d=self.dialogue[key]
        ans=d["alibi"] if qt=="alibi" else d["motive"]+" But I did not murder him." if qt=="motive" else d["rel"]
        self.open_interview(key,ans)

    def open_facts(self):
        s,h=build_facts(self.facts,self._MW(),self.F); self.modal.open("  CONFIRMED CASE FACTS",s,h)

    def open_notebook(self):
        s,h=build_notebook(self.facts,self.visited,self.clues,self.notebook,self._MW(),self.F)
        self.modal.open("  DETECTIVE NOTEBOOK",s,h)

    def handle(self):
        for ev in pygame.event.get():
            if ev.type==pygame.QUIT: pygame.quit(); sys.exit()
            # Global keys
            if ev.type==pygame.KEYDOWN:
                if ev.key==pygame.K_F11 or (ev.key==pygame.K_RETURN and ev.mod&pygame.KMOD_ALT):
                    self.toggle_fs(); continue
                if ev.key==pygame.K_h and not any([self.modal.vis,self.nbedit.vis,self.accuse.vis]):
                    self.help.toggle(); continue
                if ev.key==pygame.K_ESCAPE:
                    if self.help.vis:   self.help.vis=False;   continue
                    if self.nbedit.vis: self.nbedit.vis=False; continue
                    if self.accuse.vis: self.accuse.vis=False; continue
                    if self.modal.vis:  self.modal.vis=False;  continue

            # Translate mouse position to canvas space for fullscreen compatibility
            # We pass canvas_pos separately to handlers that need it
            # For mouse events use ev.pos; for wheel use current mouse position
            if hasattr(ev, 'pos'):
                cpos = self.to_canvas(ev.pos)
            elif ev.type == pygame.MOUSEWHEEL:
                cpos = self.to_canvas(pygame.mouse.get_pos())
            else:
                cpos = None

            # Help takes priority over everything
            if self.help.vis: self.help.handle(ev, cpos); continue

            # Overlays
            if self.nbedit.vis: self.nbedit.handle(ev, self.notebook, cpos); continue
            if self.accuse.vis: self.accuse.handle(ev, self.sol, self, cpos); continue
            if self.modal.vis:  self.modal.handle(ev, self, cpos); continue

            # ? button always available (when no overlay)
            if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1 and self.btn_q.hit(self.to_canvas(ev.pos)):
                self.help.toggle(); continue
            if ev.type==pygame.MOUSEMOTION: self.btn_q.update(self.to_canvas(ev.pos))

            if self.state==self.I1:
                if ev.type==pygame.MOUSEMOTION: self.btn_beg.update(self.to_canvas(ev.pos))
                if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
                    if self.btn_beg.hit(self.to_canvas(ev.pos)): self.state=self.I2

            elif self.state==self.I2:
                if ev.type==pygame.MOUSEMOTION: self.btn_inv.update(self.to_canvas(ev.pos))
                if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
                    if self.btn_inv.hit(self.to_canvas(ev.pos)): self.state=self.PLAY

            else:
                if ev.type==pygame.MOUSEMOTION:
                    pos=self.to_canvas(ev.pos); self.hov_hs=None
                    for hk,h in self.hs.items():
                        dx,dy=pos[0]-h["cx"],pos[1]-h["cy"]
                        if dx*dx+dy*dy<=(h["r"]+8)**2: self.hov_hs=hk; break
                    for c in self.cards: c["hov"]=c["rect"].collidepoint(pos)
                    self.btn_nb.update(pos); self.btn_cf.update(pos); self.btn_acc.update(pos)
                if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==1:
                    pos=self.to_canvas(ev.pos)
                    if self.btn_nb.hit(pos):  self.open_notebook(); continue
                    if self.btn_cf.hit(pos):  self.open_facts();    continue
                    if self.btn_acc.hit(pos): self.accuse.show();   continue
                    hit=False
                    for hk,h in self.hs.items():
                        dx,dy=pos[0]-h["cx"],pos[1]-h["cy"]
                        if dx*dx+dy*dy<=(h["r"]+8)**2:
                            h["vis"]=True
                            if hk not in self.visited: self.visited.append(hk)
                            self.open_loc(hk); hit=True; break
                    if not hit:
                        for c in self.cards:
                            if c["rect"].collidepoint(pos): self.open_interview(c["key"]); break
                if ev.type==pygame.MOUSEBUTTONDOWN and ev.button==3:
                    pos=self.to_canvas(ev.pos)
                    for c in self.cards:
                        if c["rect"].collidepoint(pos): self.nbedit.show(c["key"],self.notebook); break

    def _draw_q_btn(self, surf):
        r=self.btn_q.r; col=YELLOW if self.btn_q.hov else GOLD
        pygame.draw.rect(surf,BLACK,pygame.Rect(r.x+3,r.y+3,r.w,r.h))
        pygame.draw.rect(surf,DARK,r); pygame.draw.rect(surf,col,r,3)
        ts=self.F["med"].render("?",True,col); surf.blit(ts,ts.get_rect(center=r.center))

    def draw_hs(self,h,hov):
        c=self.canvas; col=GREEN if h["vis"] else RED
        h["pulse"]=(h["pulse"]+3)%360
        pr=h["r"]+(0 if h["vis"] else int(5*abs(math.sin(math.radians(h["pulse"])))))
        gl=pygame.Surface((pr*6,pr*6),pygame.SRCALPHA)
        pygame.draw.circle(gl,(*col,0 if h["vis"] else 55),(pr*3,pr*3),pr*3)
        c.blit(gl,(h["cx"]-pr*3,h["cy"]-pr*3))
        pygame.draw.circle(c,BLACK,(h["cx"]+2,h["cy"]+2),h["r"]+2)
        pygame.draw.circle(c,col,  (h["cx"],h["cy"]),h["r"])
        pygame.draw.circle(c,YELLOW,(h["cx"],h["cy"]),h["r"],3)
        pygame.draw.circle(c,BLACK, (h["cx"],h["cy"]),h["r"]+3,2)
        if hov:
            ts=self.F["sm"].render(h["label"],True,YELLOW)
            bw=ts.get_width()+18; bh=ts.get_height()+12
            bx=h["cx"]-bw//2; by=h["cy"]-h["r"]-bh-10
            pygame.draw.rect(c,BLACK,pygame.Rect(bx+2,by+2,bw,bh))
            pygame.draw.rect(c,DARK, pygame.Rect(bx,by,bw,bh))
            pygame.draw.rect(c,YELLOW,pygame.Rect(bx,by,bw,bh),2)
            c.blit(ts,(bx+9,by+6))

    def draw_card(self,cd):
        c=self.canvas; key=cd["key"]; r=cd["rect"]
        oy=-12 if cd["hov"] else 0
        sp=self.sprites[key]
        sx=r.x+(r.w-sp.get_width())//2; sy=r.y+r.h-sp.get_height()-28
        c.blit(sp,(sx,sy+oy))
        ts=self.F["sm"].render(SUSPECT_DATA[key]["name"],True,YELLOW if cd["hov"] else CREAM)
        c.blit(ts,ts.get_rect(centerx=r.x+r.w//2,y=r.y+r.h-26+oy))

    def draw_hud(self):
        c=self.canvas
        pygame.draw.rect(c,DARK,pygame.Rect(0,0,W,HUD_H))
        pygame.draw.rect(c,YELLOW,pygame.Rect(0,HUD_H-3,W,3))
        t=self.F["med"].render("CAMPUS KILLER",True,RED); c.blit(t,(70,12))
        s=self.F["body"].render("IE UNIVERSITY  MADRID",True,YELLOW); c.blit(s,(70+t.get_width()+22,16))
        self.btn_nb.draw(c); self.btn_cf.draw(c); self.btn_acc.draw(c)
        self._draw_q_btn(c)

    def draw_bar(self):
        c=self.canvas; by=H-BAR_H
        pygame.draw.rect(c,DARK,pygame.Rect(0,by,W,BAR_H))
        pygame.draw.rect(c,YELLOW,pygame.Rect(0,by,W,3))
        for cd in self.cards: self.draw_card(cd)

    def draw_intro(self,n):
        c=self.canvas; c.blit(self.bg,(0,0))
        ov=pygame.Surface((W,H),pygame.SRCALPHA); ov.fill((0,0,0,205)); c.blit(ov,(0,0))
        F=self.F
        self._draw_q_btn(c)
        if n==1:
            t=F["title"].render("CAMPUS KILLER",True,RED); c.blit(t,t.get_rect(centerx=W//2,y=H//2-195))
            s=F["med"].render("IE UNIVERSITY MURDER MYSTERY",True,YELLOW); c.blit(s,s.get_rect(centerx=W//2,y=H//2-145))
            lines=["A murder has been committed at IE University.",
                   "Professor I is dead.",
                   "You are the only detective on campus.",
                   "Find the killer before they disappear."]
            y=H//2-82
            for ln in lines:
                ts=F["body"].render(ln,True,CREAM); c.blit(ts,ts.get_rect(centerx=W//2,y=y)); y+=F["body"].get_linesize()+12
            self.btn_beg.update(self.to_canvas(pygame.mouse.get_pos())); self.btn_beg.draw(c)
        else:
            t=F["title"].render("CASE BRIEFING",True,YELLOW); c.blit(t,t.get_rect(centerx=W//2,y=50))
            s=F["body"].render("Prof. I found dead. Two facts confirmed by investigators:",True,CREAM)
            c.blit(s,s.get_rect(centerx=W//2,y=104))
            y=148
            for i,fact in enumerate(self.facts):
                wl=wrap(fact,F["body"],W-260)
                y=fact_box(c,F,"CONFIRMED FACT "+str(i+1),wl,100,y,W-200)
            self.btn_inv.update(self.to_canvas(pygame.mouse.get_pos())); self.btn_inv.draw(c)

    def draw_play(self):
        c=self.canvas; c.blit(self.bg,(0,0))
        ov=pygame.Surface((W,H),pygame.SRCALPHA)
        for row in range(H): pygame.draw.line(ov,(0,0,12,int(row/H*140)),(0,row),(W,row))
        c.blit(ov,(0,0))
        for hk,h in self.hs.items(): self.draw_hs(h,self.hov_hs==hk)
        self.draw_hud(); self.draw_bar()

    def scale_to_window(self):
        sw,sh=self.screen.get_size()
        if (sw,sh)==(W,H): self.screen.blit(self.canvas,(0,0))
        else: self.screen.blit(pygame.transform.smoothscale(self.canvas,(sw,sh)),(0,0))

    def to_canvas(self, pos):
        """Translate screen mouse coords to canvas coords."""
        sw,sh=self.screen.get_size()
        if sw==0 or sh==0: return pos
        return (int(pos[0]*W/sw), int(pos[1]*H/sh))

    def run(self):
        while True:
            self.handle()
            if   self.state==self.I1: self.draw_intro(1)
            elif self.state==self.I2: self.draw_intro(2)
            else:
                self.draw_play()
                self.modal.draw(self.canvas)
                self.accuse.draw(self.canvas,self.F)
                self.nbedit.draw(self.canvas)
            # Help always draws on top regardless of state
            self.help.draw(self.canvas,self.F)
            self.scale_to_window()
            pygame.display.flip()
            self.clock.tick(60)

if __name__=="__main__":
    Game().run()
